seq, err := svc.ExportSyntheticMeterDataIter(ctx, params)
if err != nil {
    return fmt.Errorf("start export: %w", err)
}
for event, iterErr := range seq {
    if iterErr != nil {
        // non-fatal: log and continue, or cancel ctx to abort
        log.Warn("export error", "err", iterErr)
        continue
    }
    if err := ingest(ctx, event); err != nil {
        return err // early break cancels producer goroutine automatically
    }
}

// In cmd/server/main.go — before initNamespace()
if err := app.NamespaceManager.RegisterHandler(myNewHandler); err != nil {
    return fmt.Errorf("register handler: %w", err)
}
// CreateDefaultNamespace fans out to all registered handlers including myNewHandler
if err := app.NamespaceManager.CreateDefaultNamespace(ctx); err != nil {
    return fmt.Errorf("create default namespace: %w", err)
}

// In httphandler/portal.go operation func:
if input.AllowedMeterSlugs != nil {
    for _, slug := range *input.AllowedMeterSlugs {
        if _, err := h.meterSvc.GetMeterByIDOrSlug(ctx, ns, slug); err != nil {
            return nil, models.NewGenericValidationError(fmt.Errorf("meter slug %q not found", slug))
        }
    }
}
token, err := h.portalSvc.CreateToken(ctx, input)
if err != nil {
    return nil, err
}
// Token field is set here — NOT inside toAPIPortalToken
apiToken := toAPIPortalToken(token)
apiToken.Token = token.Token

// Upsert
upsertInput := entity.UpsertProgressInput{
    Namespace: ns,
    ID:        opID,
    Progress:  entity.Progress{Total: 100, Completed: 50, UpdatedAt: time.Now()},
}
if err := upsertInput.Validate(); err != nil {
    return fmt.Errorf("invalid upsert input: %w", err)
}
if err := svc.UpsertProgress(ctx, upsertInput); err != nil {
    return err
}

// Get
getInput := entity.GetProgressInput{Namespace: ns, ID: opID}
if err := getInput.Validate(); err != nil {
    return fmt.Errorf("invalid get input: %w", err)
}
progress, err := svc.GetProgress(ctx, getInput)
if err != nil {
    // models.GenericNotFoundError if key expired or never set
    return err
}
